const tagContainer=document.getElementById("tag-container");fetch("/api/tags?sort=post_count&order=desc").then(response=>{response.json().then(json=>{json.data.forEach(tag=>{var tagListItem=document.createElement("li"),tagLink=document.createElement("a");tagLink.href=`/posts/?tags=${tag.name}`,tag.name.length>15?tagLink.innerText=`${tag.name.slice(0,15)}... ${tag.post_count}`:tagLink.innerText=`${tag.name} ${tag.post_count}`,tagLink.classList.add("tag-list-item"),tagLink.classList.add(tag.type),tagListItem.appendChild(tagLink),tagContainer.appendChild(tagListItem)})})});